#!/usr/bin/env python3\n\"\"\"\n07_fit_phase.py — Fit polariton centroid to phase modulation model.\n\nSub-Experiment B (Phase sweep):\n    Model: x̄_pol(φ_spatial) = m · φ_spatial + b\n\nReads aggregated centroid_x_mean_um values at different spatial phase ramp\nvalues, fits a linear model, and outputs results to JSON.\n\nUsage:\n    python scripts/07_fit_phase.py --input aggregated_phase_data.csv \\\\\n                                   --output fit_phase_results.json\n\"\"\"\n\nimport argparse\nimport json\nimport logging\nfrom pathlib import Path\n\nimport numpy as np\nfrom scipy import stats\n\nlogger = logging.getLogger(__name__)\nlogging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')\n\n\ndef fit_phase_sweep(phi_spatial_array, centroid_array, centroid_std_array=None, n_bootstrap=10000):\n    \"\"\"\n    Fit linear model to phase modulation data.\n    \n    Args:\n        phi_spatial_array: array of spatial phase ramp values (rad/µm)\n        centroid_array: array of centroid positions (µm)\n        centroid_std_array: optional array of centroid standard deviations (µm)\n        n_bootstrap: number of bootstrap resamples for CI estimation\n    \n    Returns:\n        Dictionary with fit results, parameters, CI, and diagnostics.\n    \"\"\"\n    # Sort by phase for plotting\n    sort_idx = np.argsort(phi_spatial_array)\n    phi_spatial = phi_spatial_array[sort_idx]\n    centroid = centroid_array[sort_idx]\n    \n    if centroid_std_array is not None:\n        centroid_std = centroid_std_array[sort_idx]\n    else:\n        centroid_std = None\n    \n    # Linear regression\n    if centroid_std is not None and np.any(centroid_std > 0):\n        # Weighted least squares\n        weights = 1.0 / (centroid_std ** 2)\n        slope, intercept, r_value, p_value, std_err = stats.linregress(\n            phi_spatial, centroid, alternative='two-sided'\n        )\n        # Note: scipy.stats.linregress doesn't directly support weights; use manual WLS\n        W = np.diag(weights)\n        X = np.column_stack([phi_spatial, np.ones_like(phi_spatial)])\n        XtWX_inv = np.linalg.inv(X.T @ W @ X)\n        params = XtWX_inv @ X.T @ W @ centroid\n        slope, intercept = params\n        cov_matrix = XtWX_inv\n        slope_std = np.sqrt(cov_matrix[0, 0])\n        intercept_std = np.sqrt(cov_matrix[1, 1])\n    else:\n        # Ordinary least squares\n        slope, intercept, r_value, p_value, std_err = stats.linregress(phi_spatial, centroid)\n        slope_std = std_err\n        # Estimate intercept std\n        n = len(centroid)\n        residuals = centroid - (slope * phi_spatial + intercept)\n        mse = np.sum(residuals ** 2) / (n - 2)\n        x_mean = np.mean(phi_spatial)\n        ss_x = np.sum((phi_spatial - x_mean) ** 2)\n        intercept_std = np.sqrt(mse * (1/n + x_mean**2 / ss_x))\n    \n    # Compute R-squared and other diagnostics\n    yhat = slope * phi_spatial + intercept\n    ss_res = np.sum((centroid - yhat) ** 2)\n    ss_tot = np.sum((centroid - np.mean(centroid)) ** 2)\n    r_squared = 1 - (ss_res / ss_tot) if ss_tot != 0 else 0\n    \n    # 95% CI from parametric approach\n    slope_ci_95 = [slope - 1.96 * slope_std, slope + 1.96 * slope_std]\n    intercept_ci_95 = [intercept - 1.96 * intercept_std, intercept + 1.96 * intercept_std]\n    \n    # Build results dictionary\n    results = {\n        'model': 'x̄_pol = m · φ_spatial + b',\n        'parameters': {\n            'slope_m_um_per_rad_per_um': float(slope),\n            'slope_m_um_per_rad_per_um_ci_95': slope_ci_95,\n            'intercept_b_um': float(intercept),\n            'intercept_b_um_ci_95': intercept_ci_95,\n        },\n        'diagnostics': {\n            'r_squared': float(r_squared),\n            'n_points': len(phi_spatial),\n            'residual_sum_of_squares': float(ss_res),\n        },\n        'data': {\n            'phi_spatial_rad_per_um': phi_spatial.tolist(),\n            'centroid_um': centroid.tolist(),\n            'centroid_std_um': (centroid_std.tolist() if centroid_std is not None else None),\n        },\n    }\n    \n    logger.info(f\"Fit complete:\")\n    logger.info(f\"  m = {slope:.4f} ± {slope_std:.4f} µm per rad/µm\")\n    logger.info(f\"  b = {intercept:.4f} ± {intercept_std:.4f} µm\")\n    logger.info(f\"  R² = {r_squared:.4f}\")\n    \n    return results\n\n\nif __name__ == '__main__':\n    parser = argparse.ArgumentParser(\n        description=\"Fit linear model to Sub-Experiment B data.\"\n    )\n    parser.add_argument(\n        '--input',\n        required=True,\n        help='Path to aggregated phase data (CSV with columns: phi_spatial_rad_per_um, centroid_um, centroid_std_um)'\n    )\n    parser.add_argument(\n        '--output',\n        required=True,\n        help='Path to write fit results (JSON)'\n    )\n    \n    args = parser.parse_args()\n    \n    # Load data\n    input_path = Path(args.input)\n    if not input_path.exists():\n        logger.error(f\"Input file not found: {input_path}\")\n        exit(1)\n    \n    data = np.genfromtxt(input_path, delimiter=',', skip_header=1, names=True)\n    \n    # Fit\n    results = fit_phase_sweep(\n        data['phi_spatial_rad_per_um'],\n        data['centroid_um'],\n        data['centroid_std_um'] if 'centroid_std_um' in data.dtype.names else None,\n    )\n    \n    # Write output\n    output_path = Path(args.output)\n    with open(output_path, 'w') as f:\n        json.dump(results, f, indent=2)\n    \n    logger.info(f\"Results written to {output_path}\")\n